CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE IF NOT EXISTS departments(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),code varchar(20) UNIQUE NOT NULL,name varchar(120) NOT NULL,sort_order int DEFAULT 0,active boolean DEFAULT true,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS services(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),code varchar(20) UNIQUE NOT NULL,name varchar(120) NOT NULL,department_code varchar(20) REFERENCES departments(code),sort_order int DEFAULT 0,active boolean DEFAULT true,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS users(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),full_name varchar(150) NOT NULL,email varchar(180) UNIQUE NOT NULL,password_hash text NOT NULL,role varchar(40) NOT NULL DEFAULT 'RH',active boolean DEFAULT true,last_login_at timestamptz,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS employees(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),employee_no varchar(30) UNIQUE NOT NULL,first_name varchar(100) NOT NULL,last_name varchar(100) NOT NULL,gender varchar(20),birth_date date,phone varchar(30),email varchar(180),address text,hire_date date NOT NULL,department_code varchar(20) REFERENCES departments(code),service_code varchar(20) REFERENCES services(code),job_title varchar(150),contract_type varchar(30),status varchar(30) DEFAULT 'ACTIF',base_salary numeric(14,2) DEFAULT 0,bank_name varchar(120),bank_account varchar(100),cnps_number varchar(80),emergency_contact_name varchar(150),emergency_contact_phone varchar(30),created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS contracts(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),employee_id uuid REFERENCES employees(id) ON DELETE CASCADE,reference varchar(40) UNIQUE NOT NULL,contract_type varchar(30) NOT NULL,start_date date NOT NULL,end_date date,trial_end_date date,job_title varchar(150),salary numeric(14,2),status varchar(30) DEFAULT 'ACTIF',document_url text,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS shifts(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),code varchar(20) UNIQUE NOT NULL,name varchar(80) NOT NULL,start_time time NOT NULL,end_time time NOT NULL,night_shift boolean DEFAULT false);
CREATE TABLE IF NOT EXISTS attendance(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),employee_id uuid REFERENCES employees(id) ON DELETE CASCADE,work_date date NOT NULL,shift_id uuid REFERENCES shifts(id),clock_in timestamptz,clock_out timestamptz,status varchar(30) DEFAULT 'PRESENT',late_minutes int DEFAULT 0,overtime_minutes int DEFAULT 0,notes text,UNIQUE(employee_id,work_date));
CREATE TABLE IF NOT EXISTS leave_requests(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),employee_id uuid REFERENCES employees(id) ON DELETE CASCADE,leave_type varchar(50) NOT NULL,start_date date NOT NULL,end_date date NOT NULL,days numeric(6,2) NOT NULL,reason text,status varchar(30) DEFAULT 'EN_ATTENTE',approved_by uuid REFERENCES users(id),created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS payroll_periods(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),period_month int NOT NULL,period_year int NOT NULL,start_date date,end_date date,status varchar(30) DEFAULT 'BROUILLON',closed_at timestamptz,UNIQUE(period_month,period_year));
CREATE TABLE IF NOT EXISTS payslips(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),period_id uuid REFERENCES payroll_periods(id) ON DELETE CASCADE,employee_id uuid REFERENCES employees(id) ON DELETE CASCADE,base_salary numeric(14,2) DEFAULT 0,overtime numeric(14,2) DEFAULT 0,bonuses numeric(14,2) DEFAULT 0,gross_salary numeric(14,2) DEFAULT 0,employee_contributions numeric(14,2) DEFAULT 0,tax numeric(14,2) DEFAULT 0,loan_deductions numeric(14,2) DEFAULT 0,other_deductions numeric(14,2) DEFAULT 0,net_salary numeric(14,2) DEFAULT 0,status varchar(30) DEFAULT 'BROUILLON',UNIQUE(period_id,employee_id));
CREATE TABLE IF NOT EXISTS loans(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),employee_id uuid REFERENCES employees(id) ON DELETE CASCADE,loan_type varchar(40) NOT NULL,amount numeric(14,2) NOT NULL,monthly_payment numeric(14,2) NOT NULL,balance numeric(14,2) NOT NULL,start_date date,status varchar(30) DEFAULT 'EN_COURS',created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS job_openings(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),title varchar(150) NOT NULL,department_code varchar(20) REFERENCES departments(code),service_code varchar(20) REFERENCES services(code),openings int DEFAULT 1,deadline date,status varchar(30) DEFAULT 'OUVERT',description text,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS candidates(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),job_id uuid REFERENCES job_openings(id) ON DELETE SET NULL,first_name varchar(100),last_name varchar(100),phone varchar(30),email varchar(180),stage varchar(40) DEFAULT 'RECU',score numeric(5,2),cv_url text,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS trainings(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),title varchar(180) NOT NULL,training_date date,trainer varchar(150),location varchar(150),status varchar(30) DEFAULT 'PLANIFIEE',validity_months int,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS training_participants(training_id uuid REFERENCES trainings(id) ON DELETE CASCADE,employee_id uuid REFERENCES employees(id) ON DELETE CASCADE,result varchar(30),certificate_url text,PRIMARY KEY(training_id,employee_id));
CREATE TABLE IF NOT EXISTS disciplinary_cases(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),reference varchar(40) UNIQUE NOT NULL,employee_id uuid REFERENCES employees(id),case_type varchar(50),incident_date date,reason text,level varchar(40),status varchar(30) DEFAULT 'OUVERT',created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS qhse_incidents(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),reference varchar(40) UNIQUE NOT NULL,incident_type varchar(60),incident_date date,area varchar(120),severity varchar(30),employee_id uuid REFERENCES employees(id),description text,corrective_action text,status varchar(30) DEFAULT 'OUVERT',created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS medical_visits(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),employee_id uuid REFERENCES employees(id),visit_date date,visit_type varchar(50),fitness_status varchar(50),next_visit_date date,restrictions text,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS ppe_items(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),code varchar(30) UNIQUE NOT NULL,name varchar(120) NOT NULL,renewal_days int,stock_quantity int DEFAULT 0,min_stock int DEFAULT 0,active boolean DEFAULT true);
CREATE TABLE IF NOT EXISTS ppe_issues(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),ppe_id uuid REFERENCES ppe_items(id),employee_id uuid REFERENCES employees(id),quantity int DEFAULT 1,issued_at date NOT NULL,next_renewal_date date,condition varchar(30) DEFAULT 'BON',created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS hr_documents(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),employee_id uuid REFERENCES employees(id),document_type varchar(70),reference varchar(50),issued_at date DEFAULT CURRENT_DATE,file_url text,status varchar(30) DEFAULT 'DISPONIBLE',created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS payroll_settings(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),setting_key varchar(80) UNIQUE NOT NULL,label varchar(150),value_numeric numeric(14,4),value_text text,effective_from date NOT NULL,active boolean DEFAULT true,updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS audit_logs(id bigserial PRIMARY KEY,user_id uuid REFERENCES users(id),action varchar(70),entity varchar(70),entity_id text,details jsonb,created_at timestamptz DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_employee_department ON employees(department_code);CREATE INDEX IF NOT EXISTS idx_attendance_date ON attendance(work_date);CREATE INDEX IF NOT EXISTS idx_payslip_period ON payslips(period_id);
